def compute_nav_control_state(returns):
    ret = pd.Series(returns).fillna(0.0)
    throttle = apply_practical_throttle(ret, V1_2_NAV_CONTROL_CFG)
    nav = (1.0 + throttle["return"].fillna(0.0)).cumprod()
    last_scale = float(throttle["scale"].iloc[-1])
    peak = float(nav.cummax().iloc[-1])
    current_dd = float(nav.iloc[-1] / peak - 1.0) if peak > 0 else 0.0
    next_scale, next_state = target_scale_from_drawdown(current_dd, V1_2_NAV_CONTROL_CFG, last_scale)
    return {
        "throttle": throttle,
        "nav": nav,
        "last_scale": last_scale,
        "last_state": str(throttle["state"].iloc[-1]),
        "current_dd": current_dd,
        "next_scale": float(next_scale),
        "next_state": str(next_state),
    }


