def read_json_cache(path, max_age_seconds):
    if max_age_seconds <= 0 or not path.exists():
        return None
    age = time.time() - path.stat().st_mtime
    if age > max_age_seconds:
        return None
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return None


def write_json_cache(path, payload):
    path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")


def resolve_csv_cache_path(local_dir, shared_dir, symbol):
    local_path = local_dir / f"{str(symbol).zfill(6)}.csv"
    if local_path.exists():
        return local_path
    if shared_dir is not None:
        shared_path = shared_dir / f"{str(symbol).zfill(6)}.csv"
        if shared_path.exists():
            return shared_path
    return None


def _parse_cn_num(text):
    raw = str(text or "").strip()
    if not raw:
        return None
    if raw.isdigit():
        return int(raw)
    if raw in CN_NUM:
        return CN_NUM[raw]
    if "十" in raw:
        parts = raw.split("十")
        tens = CN_NUM.get(parts[0], 1) if parts[0] else 1
        ones = CN_NUM.get(parts[1], 0) if len(parts) > 1 and parts[1] else 0
        return tens * 10 + ones
    return None


def _strip_query_prefix(text):
    out = re.sub(r"^(查询|看看|看下|看一下|给我看一个|给我看看)", "", str(text or "").strip())
    out = re.sub(r"^(表现|净值曲线|收益|回撤|年化|夏普|回报)", "", out)
    out = re.sub(r"^[:：\s]+", "", out)
    return out.strip()


def parse_date_range(text, now=None):
    now = (now or pd.Timestamp.now()).normalize()
    raw = str(text or "").strip()
    text = re.sub(r"\s+", "", raw).replace("份", "")
    text = _strip_query_prefix(text)
    if not text or text in {"全部", "全样本", "历史全部", "历史", "全周期"}:
        return None, None, "全样本"

    m = re.search(
        r"(\d{4})[-年/.](\d{1,2})[-月/.](\d{1,2})" + DAY_SUFFIX +
        r"[到至~—-]+" +
        r"(\d{4})[-年/.](\d{1,2})[-月/.](\d{1,2})" + DAY_SUFFIX,
        text,
    )
    if m:
        start = pd.Timestamp(f"{m.group(1)}-{int(m.group(2)):02d}-{int(m.group(3)):02d}")
        end = pd.Timestamp(f"{m.group(4)}-{int(m.group(5)):02d}-{int(m.group(6)):02d}")
        return start, end, f"{start:%Y-%m-%d} to {end:%Y-%m-%d}"

    m = re.search(r"(\d{4})[-年/.](\d{1,2})[-月/.](\d{1,2})" + DAY_SUFFIX + r"至今", text)
    if m:
        start = pd.Timestamp(f"{m.group(1)}-{int(m.group(2)):02d}-{int(m.group(3)):02d}")
        return start, now, f"{start:%Y-%m-%d} to now"

    m = re.search(r"(\d{4})[-年/.]?(\d{1,2})[-月]?\s*至今", text)
    if m:
        start = pd.Timestamp(f"{m.group(1)}-{int(m.group(2)):02d}-01")
        return start, now, f"{start:%Y-%m} to now"

    m = re.search(r"(\d{4})\s*年?\s*至今", text)
    if m:
        start = pd.Timestamp(f"{m.group(1)}-01-01")
        return start, now, f"{start:%Y} to now"

    m = re.search(r"(\d{4})[-年/.]?(\d{1,2})[-月]?[到至~—-]+(\d{4})[-年/.]?(\d{1,2})", text)
    if m:
        start = pd.Timestamp(f"{m.group(1)}-{int(m.group(2)):02d}-01")
        end = pd.Timestamp(f"{m.group(3)}-{int(m.group(4)):02d}-01") + pd.offsets.MonthEnd(0)
        return start, end, f"{start:%Y-%m} to {end:%Y-%m}"

    m = re.search(r"(\d{4})\s*年?\s*[到至~—-]\s*(\d{4})\s*年?", text)
    if m:
        start = pd.Timestamp(f"{m.group(1)}-01-01")
        end = pd.Timestamp(f"{m.group(2)}-12-31")
        return start, end, f"{m.group(1)} to {m.group(2)}"

    m = re.search(r"(?:最近|过去|近)([一二两三四五六七八九十\d半]+)个?年", text)
    if m:
        n = _parse_cn_num(m.group(1))
        if n is not None:
            start = now - pd.DateOffset(months=int(n * 12)) if isinstance(n, float) else now - pd.DateOffset(years=int(n))
            return start, now, f"last_{m.group(1)}_years"

    m = re.search(r"(?:最近|过去|近)([一二两三四五六七八九十\d半]+)个?月", text)
    if m:
        n = _parse_cn_num(m.group(1))
        if n is not None:
            months = int(n if n >= 1 else 1)
            start = now - pd.DateOffset(months=months)
            return start, now, f"last_{m.group(1)}_months"

    if "今年" in text:
        start = pd.Timestamp(f"{now.year}-01-01")
        return start, now, f"{now.year}"
    if "去年" in text:
        year = now.year - 1
        return pd.Timestamp(f"{year}-01-01"), pd.Timestamp(f"{year}-12-31"), f"{year}"

    m = re.search(r"(\d{4})[-年/.](\d{1,2})\s*月?$", text)
    if m:
        start = pd.Timestamp(f"{m.group(1)}-{int(m.group(2)):02d}-01")
        end = start + pd.offsets.MonthEnd(0)
        return start, end, f"{start:%Y-%m}"

    m = re.search(r"(\d{4})\s*年?$", text)
    if m:
        year = int(m.group(1))
        if 2000 <= year <= 2099:
            return pd.Timestamp(f"{year}-01-01"), pd.Timestamp(f"{year}-12-31"), f"{year}"

    return None, None, "全样本"


def calc_metrics_from_returns(returns):
    series = pd.Series(returns).fillna(0.0).astype(float)
    nav = (1.0 + series).cumprod()
    years = max(len(series) / 252.0, 1e-9)
    annual = float(nav.iloc[-1] ** (1.0 / years) - 1.0) if len(nav) else 0.0
    vol = float(series.std(ddof=0) * np.sqrt(252)) if len(series) else 0.0
    sharpe = annual / vol if vol > 1e-12 else 0.0
    max_dd = float((nav / nav.cummax() - 1.0).min()) if len(nav) else 0.0
    return {
        "annual": annual,
        "vol": vol,
        "sharpe": sharpe,
        "max_dd": max_dd,
    }


def load_embedded_performance_source():
    blob = str(get_strategy().get("embedded_performance_b64") or "").strip()
    if not blob or blob.startswith("__EMBEDDED_"):
        return None
    try:
        raw = zlib.decompress(base64.b64decode(blob)).decode("utf-8")
        perf = pd.read_csv(io.StringIO(raw))
    except Exception as exc:
        raise RuntimeError(f"内嵌表现数据解压失败：{exc}") from exc
    if "date" not in perf.columns:
        raise RuntimeError("内嵌表现数据缺少 date 列。")
    perf["date"] = pd.to_datetime(perf["date"])
    perf = perf.set_index("date").sort_index()
    if "return_net" not in perf.columns and "nav_net" in perf.columns:
        perf["return_net"] = perf["nav_net"].pct_change().fillna(0.0)
    if "nav_net" not in perf.columns and "return_net" in perf.columns:
        perf["nav_net"] = (1.0 + perf["return_net"].fillna(0.0)).cumprod()
    if "return_net" not in perf.columns or "nav_net" not in perf.columns:
        raise RuntimeError("内嵌表现数据缺少 return_net/nav_net 列。")
    return perf, "return_net", "nav_net", "embedded", "embedded://performance_nav"


def load_performance_source():
    strategy = get_strategy()
    embedded = load_embedded_performance_source()
    if embedded is not None:
        return embedded
    for source_label, path in (
        ("costed", strategy["performance_costed_nav_csv"]),
        ("gross", strategy["performance_live_nav_csv"]),
    ):
        if not path.exists():
            continue
        perf = pd.read_csv(path)
        perf["date"] = pd.to_datetime(perf["date"])
        perf = perf.set_index("date").sort_index()
        if "return_net" in perf.columns and "nav_net" in perf.columns:
            return perf, "return_net", "nav_net", source_label, path
        if "return" in perf.columns and "nav" in perf.columns:
            return perf, "return", "nav", source_label, path
    raise RuntimeError("未找到可用的表现数据源，当前版本无法生成表现图表。")


def build_performance_outputs(query_text):
    perf_df, ret_col, nav_col, source_label, source_path = load_performance_source()
    start_date, end_date, period_label = parse_date_range(query_text)
    data = perf_df.copy()
    if start_date is None:
        start_date = pd.Timestamp(data.index.min())
    if end_date is None:
        end_date = pd.Timestamp(data.index.max())
    data = data.loc[(data.index >= start_date) & (data.index <= end_date)].copy()
    if data.empty:
        raise RuntimeError(f"在 {start_date:%Y-%m-%d} 到 {end_date:%Y-%m-%d} 之间没有表现数据。")

    returns = data[ret_col].fillna(0.0)
    metrics = calc_metrics_from_returns(returns)
    data["nav_rebased"] = (1.0 + returns).cumprod()
    data["drawdown"] = data["nav_rebased"] / data["nav_rebased"].cummax() - 1.0

    yearly_rows = []
    for year, part in data.groupby(data.index.year):
        part_returns = part[ret_col].fillna(0.0)
        part_metrics = calc_metrics_from_returns(part_returns)
        yearly_rows.append(
            {
                "year": str(year),
                "start_date": str(part.index.min().date()),
                "end_date": str(part.index.max().date()),
                "days": int(len(part)),
                "return_pct": float((1.0 + part_returns).prod() - 1.0) * 100.0,
                "max_drawdown_pct": float(part_metrics["max_dd"]) * 100.0,
                "sharpe": float(part_metrics["sharpe"]),
                "annual_pct": float(part_metrics["annual"]) * 100.0,
            }
        )
    yearly_df = pd.DataFrame(yearly_rows)
    summary = {
        "period_label": period_label,
        "source": source_label,
        "source_file": str(source_path),
        "start_date": str(data.index.min().date()),
        "end_date": str(data.index.max().date()),
        "days": int(len(data)),
        "final_nav": float(data["nav_rebased"].iloc[-1]),
        "total_return_pct": float(data["nav_rebased"].iloc[-1] - 1.0) * 100.0,
        "annual_pct": float(metrics["annual"]) * 100.0,
        "max_drawdown_pct": float(metrics["max_dd"]) * 100.0,
        "sharpe": float(metrics["sharpe"]),
        "vol_pct": float(metrics["vol"]) * 100.0,
    }

    chart_bytes = None
    if plt is not None:
        fig, (ax1, ax2) = plt.subplots(2, 1, figsize=(12, 7), sharex=True, gridspec_kw={"height_ratios": [3, 1]})
        ax1.plot(data.index, data["nav_rebased"], linewidth=2.0, color="#1f4e79")
        ax1.set_title(f"Top100 Performance {get_strategy_label()} ({summary['start_date']} to {summary['end_date']})")
        ax1.set_ylabel("Rebased NAV")
        ax1.grid(True, alpha=0.25)
        ax2.fill_between(data.index, data["drawdown"] * 100.0, 0.0, color="#c0392b", alpha=0.25)
        ax2.plot(data.index, data["drawdown"] * 100.0, color="#c0392b", linewidth=1.2)
        ax2.axhline(0.0, color="#666666", linewidth=1.0)
        ax2.set_ylabel("DD %")
        ax2.grid(True, alpha=0.25)
        fig.tight_layout()
        buf = io.BytesIO()
        fig.savefig(buf, dpi=160, format="png", bbox_inches="tight")
        plt.close(fig)
        chart_bytes = buf.getvalue()

    nav_csv = data.reset_index().to_csv(index=False).encode("utf-8-sig")
    yearly_csv = yearly_df.to_csv(index=False).encode("utf-8-sig")
    lines = [
        "表现汇总",
        f"- 策略版本：{get_strategy_label()}",
        f"- 固定对冲比：{get_strategy_hedge_ratio():.1f}x",
        f"- 区间：{summary['start_date']} 到 {summary['end_date']}",
        f"- 来源：{summary['source']}",
        f"- 区间收益：{summary['total_return_pct']:.2f}%",
        f"- 年化收益：{summary['annual_pct']:.2f}%",
        f"- 最大回撤：{summary['max_drawdown_pct']:.2f}%",
        f"- 夏普：{summary['sharpe']:.2f}",
        f"- 波动率：{summary['vol_pct']:.2f}%",
    ]
    if not yearly_df.empty:
        last_rows = yearly_df.tail(min(5, len(yearly_df)))
        lines.extend(["", "年度分解"])
        for row in last_rows.itertuples(index=False):
            lines.append(f"- {row.year}：收益 {row.return_pct:.2f}% / 回撤 {row.max_drawdown_pct:.2f}% / 夏普 {row.sharpe:.2f}")
    attachments = [
        (versioned_attachment_name("top100_performance_nav.csv"), nav_csv, "text/csv"),
        (versioned_attachment_name("top100_performance_yearly.csv"), yearly_csv, "text/csv"),
    ]
    if chart_bytes is not None:
        attachments.insert(0, (versioned_attachment_name("top100_performance_curve.png"), chart_bytes, "image/png"))
    return "\n".join(lines), attachments


def df_records_with_dates(frame):
    if frame is None or len(frame) == 0:
        return []
    work = frame.copy()
    for col in work.columns:
        if pd.api.types.is_datetime64_any_dtype(work[col]):
            work[col] = pd.to_datetime(work[col]).dt.strftime("%Y-%m-%d")
    return work.to_dict(orient="records")


def serialize_context(context):
    close_df = context["close_df"].reset_index()
    if "date" in close_df.columns:
        close_df["date"] = pd.to_datetime(close_df["date"]).dt.strftime("%Y-%m-%d")
    latest_signal = context["latest_signal"].copy()
    if "date" in latest_signal.columns:
        latest_signal["date"] = pd.to_datetime(latest_signal["date"]).dt.strftime("%Y-%m-%d")
    effective_members = context["effective_members"].copy()
    target_members = context.get("target_members")
    changes_df = context.get("changes_df")
    return {
        "close_df": close_df.to_dict(orient="records"),
        "latest_signal": latest_signal.to_dict(orient="records"),
        "target_members": df_records_with_dates(target_members),
        "effective_members": df_records_with_dates(effective_members),
        "changes_df": df_records_with_dates(changes_df),
        "latest_rebalance": context["latest_rebalance"],
        "prev_rebalance": context["prev_rebalance"],
        "next_rebalance": context["next_rebalance"],
        "effective_rebalance": context["effective_rebalance"],
        "rebalance_effective_date": context["rebalance_effective_date"],
        "freshness": context["freshness"],
        "rebuild_meta": context["rebuild_meta"],
    }


def deserialize_context(payload):
    close_df = pd.DataFrame(payload.get("close_df") or [])
    if close_df.empty:
        return None
    close_df["date"] = pd.to_datetime(close_df["date"])
    close_df = close_df.sort_values("date").set_index("date")

    latest_signal = pd.DataFrame(payload.get("latest_signal") or [])
    if latest_signal.empty:
        return None
    if "date" in latest_signal.columns:
        latest_signal["date"] = pd.to_datetime(latest_signal["date"])

    target_members = pd.DataFrame(payload.get("target_members") or [])
    effective_members = pd.DataFrame(payload.get("effective_members") or [])
    changes_df = pd.DataFrame(payload.get("changes_df") or [])
    context = {
        "close_df": close_df,
        "result": result,
        "latest_signal": latest_signal,
        "target_members": target_members,
        "effective_members": effective_members,
        "changes_df": changes_df,
        "latest_rebalance": payload.get("latest_rebalance"),
        "prev_rebalance": payload.get("prev_rebalance"),
        "next_rebalance": payload.get("next_rebalance"),
        "effective_rebalance": payload.get("effective_rebalance"),
        "rebalance_effective_date": payload.get("rebalance_effective_date"),
        "freshness": payload.get("freshness") or {},
        "rebuild_meta": payload.get("rebuild_meta") or {},
    }


def is_exact_context(context):
    meta = context.get("rebuild_meta") or {}
    return int(meta.get("effective_member_count", 0)) == TOP_N


def context_signal_signature(context):
    row = context["latest_signal"].iloc[0]
    target_members = context.get("target_members")
    target_sig = ()
    if isinstance(target_members, pd.DataFrame) and not target_members.empty and "symbol" in target_members.columns:
        target_sig = tuple(target_members["symbol"].astype(str).str.zfill(6).tolist())
    changes_df = context.get("changes_df")
    changes_sig = ()
    if isinstance(changes_df, pd.DataFrame) and not changes_df.empty and {"action", "symbol"}.issubset(changes_df.columns):
        changes_sig = tuple(
            f"{str(action)}:{str(symbol).zfill(6)}"
            for action, symbol in zip(changes_df["action"].astype(str), changes_df["symbol"].astype(str))
        )
    return (
        str(row.get("next_holding")),
        str(row.get("trade_state")),
        str(context.get("latest_rebalance")),
        str(context.get("effective_rebalance")),
        target_sig,
        changes_sig,
    )


def is_context_fresh_for_trade_date(context, latest_trade_date):
    freshness = (context or {}).get("freshness") or {}
    cached_trade_date = freshness.get("latest_trade_date")
    if not cached_trade_date:
        return False
    try:
        return pd.Timestamp(cached_trade_date) >= pd.Timestamp(latest_trade_date)
    except Exception:
        return False


def has_complete_member_tables(context):
    return (
        isinstance((context or {}).get("target_members"), pd.DataFrame)
        and isinstance((context or {}).get("effective_members"), pd.DataFrame)
        and isinstance((context or {}).get("changes_df"), pd.DataFrame)
    )


def read_context_cache(force_refresh=False):
    if force_refresh:
        return None
    payload = read_json_cache(context_cache_path(), DEFAULT_CONTEXT_CACHE_SECONDS)
    if payload is None:
        return None
    try:
        return deserialize_context(payload)
    except Exception:
        return None


def write_context_cache(context):
    try:
        write_json_cache(context_cache_path(), serialize_context(context))
    except Exception:
        pass


def fetch_json(url, headers=None, timeout=DEFAULT_REQUEST_TIMEOUT, retries=5):
    last_error = None
    for attempt in range(retries):
        try:
            resp = SESSION.get(url, headers=headers or {}, timeout=timeout)
            resp.raise_for_status()
            return resp.json()
        except Exception as exc:
            last_error = exc
            time.sleep(0.8 * (attempt + 1))
    raise RuntimeError(f"请求失败: {url} | {last_error}")


