def versioned_attachment_name(file_name):
    path = Path(str(file_name))
    suffix = f"_{get_strategy_cache_tag()}"
    return f"{path.stem}{suffix}{path.suffix}"


def annotate_trade_states(result):
    out = result.copy()
    current_holding = out["holding"].astype(str)
    next_holding = out["next_holding"].astype(str)
    out["trade_state_calc"] = np.where(
        current_holding == next_holding,
        "hold",
        np.where(
            (current_holding == "cash") & (next_holding != "cash"),
            "open",
            np.where((current_holding != "cash") & (next_holding == "cash"), "close", "switch"),
        ),
    )
    return out


def get_last_trade_signal_info(context):
    meta = (context or {}).get("rebuild_meta") or {}
    cached_date = str(meta.get("last_trade_signal_date") or "").strip()
    cached_action = str(meta.get("last_trade_signal_action") or "").strip()
    if cached_date:
        return cached_date, cached_action or None

    result = (context or {}).get("result")
    if result is None:
        close_df = (context or {}).get("close_df")
        if isinstance(close_df, pd.DataFrame) and not close_df.empty:
            try:
                result = run_backtest(close_df)
            except Exception:
                result = None
    if result is None or result.empty:
        return None, None

    annotated = annotate_trade_states(result)
    changed = annotated.loc[annotated["trade_state_calc"] != "hold"]
    if changed.empty:
        return None, None
    last = changed.iloc[-1]
    return str(pd.Timestamp(changed.index[-1]).date()), str(last["trade_state_calc"])


def format_threshold_text(momentum_gap):
    gap = float(momentum_gap)
    if gap >= 0:
        return f"高于翻多阈值 {abs(gap):.2%}"
    return f"低于翻多阈值 {abs(gap):.2%}"


def classify_tail_jitter_risk(momentum_gap):
    abs_gap = abs(float(momentum_gap))
    if abs_gap < TAIL_JITTER_WARNING_GAP:
        return "warning", "动量差非常接近 0，临近收盘建议再次确认"
    if abs_gap < TAIL_JITTER_CAUTION_GAP:
        return "caution", "动量差较窄，收盘前仍有反转可能"
    return "normal", ""


def eastmoney_index_history(secid, calendar_days, force_refresh=False):
    cache = cached_path(f"index_hist_{secid.replace('.', '_')}_{calendar_days}.json")
    fresh_cached = None if force_refresh else read_json_cache(cache, 12 * 3600)
    any_cached = read_json_cache(cache, 3650 * 86400)
    if fresh_cached is not None:
        frame = pd.DataFrame(fresh_cached)
        frame["date"] = pd.to_datetime(frame["date"])
        if not frame.empty:
            return frame.sort_values("date").drop_duplicates(subset="date").reset_index(drop=True)

    end_ts = pd.Timestamp.now().normalize()
    start_ts = end_ts - pd.Timedelta(days=max(10, int(calendar_days)))
    url = (
        "https://push2his.eastmoney.com/api/qt/stock/kline/get"
        f"?secid={secid}"
        "&fields1=f1,f2,f3,f4,f5,f6"
        "&fields2=f51,f52,f53,f54,f55,f56,f57,f58,f59,f60,f61"
        "&klt=101&fqt=1"
        f"&beg={start_ts.strftime('%Y%m%d')}"
        f"&end={end_ts.strftime('%Y%m%d')}"
        "&lmt=10000"
    )
    rows = []
    try:
        data = fetch_json(
            url,
            headers={"Referer": "https://quote.eastmoney.com/"},
        ).get("data") or {}
        klines = data.get("klines") or []
        for item in klines:
            parts = item.split(",")
            if len(parts) < 3:
                continue
            rows.append({"date": pd.to_datetime(parts[0]), "close": float(parts[2])})
    except Exception:
        rows = []

    if not rows:
        if any_cached is not None:
            frame = pd.DataFrame(any_cached)
            if not frame.empty:
                frame["date"] = pd.to_datetime(frame["date"], errors="coerce")
                frame = frame.dropna(subset=["date"]).sort_values("date").drop_duplicates(subset="date").reset_index(drop=True)
                if not frame.empty:
                    return frame
        code = secid.split(".")[-1]
        market_prefix = "sh" if str(secid).startswith("1.") else "sz"
        tencent_symbol = f"{market_prefix}{code}"
        tencent_len = max(120, int(calendar_days) * 3)
        tencent_url = (
            "https://web.ifzq.gtimg.cn/appstock/app/kline/kline"
            f"?param={tencent_symbol},day,,,{tencent_len}"
        )
        try:
            data = fetch_json(tencent_url, timeout=min(DEFAULT_REQUEST_TIMEOUT, 6), retries=2)
            payload = (data.get("data") or {}).get(tencent_symbol) or {}
            klines = payload.get("day") or []
            for item in klines:
                if not isinstance(item, list) or len(item) < 3:
                    continue
                dt = pd.to_datetime(item[0], errors="coerce")
                if pd.isna(dt) or dt < start_ts or dt > end_ts:
                    continue
                rows.append({"date": dt, "close": float(item[2])})
        except Exception:
            rows = []

    if not rows:
        code = secid.split(".")[-1]
        sina_symbol = f"sh{code}"
        sina_url = (
            "https://money.finance.sina.com.cn/quotes_service/api/json_v2.php/CN_MarketData.getKLineData"
            f"?symbol={sina_symbol}&scale=240&ma=no&datalen=6000"
        )
        data = fetch_json(sina_url)
        if not isinstance(data, list):
            raise RuntimeError(f"无法获取指数历史: {secid}")
        for item in data:
            day = item.get("day")
            close = item.get("close")
            if day is None or close is None:
                continue
            dt = pd.to_datetime(day)
            if dt < start_ts or dt > end_ts:
                continue
            rows.append({"date": dt, "close": float(close)})

    out = pd.DataFrame(rows)
    if out.empty:
        raise RuntimeError(f"无法获取指数历史: {secid}")
    out = out.sort_values("date").drop_duplicates(subset="date").reset_index(drop=True)
    write_json_cache(
        cache,
        [{"date": str(pd.Timestamp(row.date).date()), "close": float(row.close)} for row in out.itertuples(index=False)],
    )
    return out


def fetch_universe_spot(cache_seconds=DEFAULT_QUOTE_CACHE_SECONDS):
    cache = cached_path("universe_spot.json")
    required_count = max(TOP_N, max(DEFAULT_POOL_STAGES + [DEFAULT_CANDIDATE_POOL]))
    target_count = max(400, required_count * 3)
    cached = read_json_cache(cache, cache_seconds)
    any_cached = read_json_cache(cache, 30 * 86400)
    if cached is not None:
        cached_df = pd.DataFrame(cached)
        if len(cached_df) >= required_count:
            return cached_df

    rows = []
    page = 1
    try:
        while True:
            url = (
                "https://push2.eastmoney.com/api/qt/clist/get"
                f"?pn={page}&pz=100&po=0&np=1&fltt=2&invt=2&fid=f20"
                "&fs=m:0+t:6,m:0+t:80,m:1+t:2,m:1+t:23"
                "&fields=f12,f14,f2,f3,f17,f18,f20"
            )
            data = fetch_json(
                url,
                headers={"Referer": "https://quote.eastmoney.com/"},
            ).get("data") or {}
            diff = data.get("diff") or []
            if not diff:
                break
            for item in diff:
                code = str(item.get("f12") or "").zfill(6)
                name = str(item.get("f14") or "")
                latest = pd.to_numeric(item.get("f2"), errors="coerce")
                market_cap = pd.to_numeric(item.get("f20"), errors="coerce")
                prev_close = pd.to_numeric(item.get("f18"), errors="coerce")
                open_price = pd.to_numeric(item.get("f17"), errors="coerce")
                if not code or pd.isna(latest) or latest <= 0 or pd.isna(market_cap) or market_cap <= 0:
                    continue
                rows.append(
                    {
                        "code": code,
                        "name": name,
                        "latest_price": float(latest),
                        "market_cap": float(market_cap),
                        "prev_close": None if pd.isna(prev_close) else float(prev_close),
                        "open_price": None if pd.isna(open_price) else float(open_price),
                    }
                )
            total = int(data.get("total") or 0)
            if len(rows) >= target_count or page * 100 >= total or page >= 20:
                break
            page += 1
    except Exception:
        rows = []

    universe = pd.DataFrame(rows).drop_duplicates(subset="code")
    if not universe.empty:
        universe = universe[
            universe["latest_price"].gt(0)
            & universe["market_cap"].gt(0)
            & ~universe["code"].astype(str).str.startswith(("8", "4"))
        ].drop_duplicates(subset="code")
    if len(universe) < required_count:
        local_universe = build_local_universe_snapshot()
        if len(local_universe) >= required_count:
            universe = local_universe
    if len(universe) < required_count and any_cached is not None:
        cached_df = pd.DataFrame(any_cached).drop_duplicates(subset="code")
        if len(cached_df) >= required_count:
            universe = cached_df
    if len(universe) < required_count:
        raise RuntimeError(
            f"无法获取足够候选股票：当前仅 {len(universe)} 只，"
            f"至少需要 {required_count} 只。"
        )
    write_json_cache(cache, universe.to_dict(orient="records"))
    return universe


def load_current_st_codes():
    try:
        if LOCAL_CURRENT_ST.exists():
            frame = pd.read_csv(LOCAL_CURRENT_ST, dtype=str)
            return set(frame["code"].dropna().astype(str).str.zfill(6))
    except Exception:
        pass
    try:
        ak = get_akshare()
        st = call_akshare_silently(ak.stock_zh_a_st_em)
        if st.empty:
            return set()
        code_col = next((col for col in st.columns if "代码" in str(col)), None)
        if code_col is None:
            return set()
        return set(st[code_col].dropna().astype(str).str.zfill(6))
    except Exception:
        return set()


def latest_market_cap_from_local_cache(symbol):
    price_path = resolve_csv_cache_path(LOCAL_PRICE_CACHE_DIR, SHARED_PRICE_CACHE_DIR, symbol)
    share_path = resolve_csv_cache_path(LOCAL_SHARE_CACHE_DIR, SHARED_SHARE_CACHE_DIR, symbol)
    if price_path is None or share_path is None:
        return None
    try:
        price = pd.read_csv(price_path, usecols=["date", "close_raw"])
        shares = pd.read_csv(share_path, usecols=["change_date", "total_shares_10k"])
    except Exception:
        return None
    if price.empty or shares.empty:
        return None
    price["date"] = pd.to_datetime(price["date"], errors="coerce")
    price["close_raw"] = pd.to_numeric(price["close_raw"], errors="coerce")
    shares["change_date"] = pd.to_datetime(shares["change_date"], errors="coerce")
    shares["total_shares_10k"] = pd.to_numeric(shares["total_shares_10k"], errors="coerce")
    price = price.dropna(subset=["date", "close_raw"]).sort_values("date")
    shares = shares.dropna(subset=["change_date", "total_shares_10k"]).sort_values("change_date")
    if price.empty or shares.empty:
        return None
    latest_price = float(price.iloc[-1]["close_raw"])
    latest_date = pd.Timestamp(price.iloc[-1]["date"])
    total_shares = float(shares.iloc[-1]["total_shares_10k"]) * 10000.0
    if latest_price <= 0 or total_shares <= 0:
        return None
    return latest_date, latest_price, latest_price * total_shares


def build_local_universe_snapshot():
    cache = cached_path("local_universe_spot.json")
    cached = read_json_cache(cache, 86400)
    if cached is not None:
        frame = pd.DataFrame(cached)
        if len(frame) >= 2000:
            return frame
    if not LOCAL_ACTIVE_UNIVERSE.exists():
        return pd.DataFrame()

    universe = pd.read_csv(LOCAL_ACTIVE_UNIVERSE, dtype=str)
    st_codes = load_current_st_codes()
    if st_codes:
        universe = universe[~universe["code"].astype(str).str.zfill(6).isin(st_codes)].copy()

    symbols = universe["code"].astype(str).str.zfill(6).tolist()
    name_map = dict(zip(universe["code"].astype(str).str.zfill(6), universe["name"].astype(str)))
    rows = []
    with ThreadPoolExecutor(max_workers=16) as pool:
        futures = {pool.submit(latest_market_cap_from_local_cache, symbol): symbol for symbol in symbols}
        for fut in as_completed(futures):
            symbol = futures[fut]
            result = fut.result()
            if result is None:
                continue
            latest_date, latest_price, market_cap = result
            rows.append(
                {
                    "code": symbol,
                    "name": name_map.get(symbol, ""),
                    "latest_date": str(pd.Timestamp(latest_date).date()),
                    "latest_price": float(latest_price),
                    "market_cap": float(market_cap),
                    "prev_close": np.nan,
                    "open_price": np.nan,
                }
            )
    frame = pd.DataFrame(rows).drop_duplicates(subset="code")
    if not frame.empty:
        write_json_cache(cache, frame.to_dict(orient="records"))
    return frame


def is_name_tradable(name):
    text = str(name or "").upper()
    if not text:
        return True
    bad_tokens = ["ST", "*ST", "退"]
    return not any(token in text for token in bad_tokens)


def select_candidate_pool(universe, pool_size, min_latest_date=None):
    frame = universe.copy()
    frame = frame[frame["name"].map(is_name_tradable)].copy()
    st_codes = load_current_st_codes()
    if st_codes:
        frame = frame[~frame["code"].astype(str).str.zfill(6).isin(st_codes)].copy()
    if min_latest_date is not None and "latest_date" in frame.columns:
        latest_dates = pd.to_datetime(frame["latest_date"], errors="coerce")
        frame = frame[latest_dates >= pd.Timestamp(min_latest_date)].copy()
    pool_size = max(TOP_N, int(pool_size))
    frame = frame.nsmallest(pool_size, "market_cap")
    return frame.reset_index(drop=True)


def load_history_cache_frame(
    symbol,
    trading_start,
    trading_end,
    min_latest_date=None,
    force_refresh=False,
    require_ohlc=False,
):
    cache = cached_path(f"hist_{symbol}.json")
    cached = None if force_refresh else read_json_cache(cache, 12 * 3600)
    if cached is None:
        return None
    frame = pd.DataFrame(cached)
    if frame.empty:
        return None
    if "close_adj" not in frame.columns:
        return None
    if require_ohlc and not {"open", "high", "low"}.issubset(frame.columns):
        return None
    frame["date"] = pd.to_datetime(frame["date"])
    if min_latest_date is not None and pd.Timestamp(frame["date"].max()) < pd.Timestamp(min_latest_date):
        return None
    frame = frame[(frame["date"] >= trading_start) & (frame["date"] <= trading_end)]
    return None if frame.empty else frame


def eastmoney_stock_history(symbol, trading_start, trading_end, min_latest_date=None, force_refresh=False):
    csv_cache_path = resolve_csv_cache_path(LOCAL_PRICE_CACHE_DIR, SHARED_PRICE_CACHE_DIR, symbol)
    if (not force_refresh) and csv_cache_path is not None:
        try:
            frame = pd.read_csv(csv_cache_path)
            frame["date"] = pd.to_datetime(frame["date"], errors="coerce")
            frame["close_raw"] = pd.to_numeric(frame["close_raw"], errors="coerce")
            if "close_adj" in frame.columns:
                frame["close_adj"] = pd.to_numeric(frame["close_adj"], errors="coerce")
            else:
                frame["close_adj"] = frame["close_raw"]
            frame = frame.dropna(subset=["date", "close_raw"]).sort_values("date")
            if min_latest_date is None or pd.Timestamp(frame["date"].max()) >= pd.Timestamp(min_latest_date):
                frame = frame[(frame["date"] >= pd.Timestamp(trading_start)) & (frame["date"] <= pd.Timestamp(trading_end))].copy()
                if not frame.empty:
                    return frame
        except Exception:
            pass

    cache = cached_path(f"hist_{symbol}.json")
    cached_frame = load_history_cache_frame(
        symbol,
        trading_start,
        trading_end,
        min_latest_date=min_latest_date,
        force_refresh=force_refresh,
    )
    if cached_frame is not None:
        return cached_frame

    rows = []
    symbol = str(symbol).zfill(6)
    market = "1" if symbol.startswith(("5", "6", "9")) else "0"
    def _eastmoney_kline_rows(fqt):
        url = (
            "https://push2his.eastmoney.com/api/qt/stock/kline/get"
            f"?secid={market}.{symbol}"
            "&fields1=f1,f2,f3,f4,f5,f6"
            "&fields2=f51,f52,f53,f54,f55,f56,f57,f58,f59,f60,f61"
            f"&klt=101&fqt={fqt}"
            f"&beg={pd.Timestamp(trading_start).strftime('%Y%m%d')}"
            f"&end={pd.Timestamp(trading_end).strftime('%Y%m%d')}"
            "&lmt=10000"
        )
        data = fetch_json(
            url,
            headers={"Referer": "https://quote.eastmoney.com/"},
            timeout=min(DEFAULT_REQUEST_TIMEOUT, 6),
            retries=3,
        ).get("data") or {}
        rows_local = []
        for item in data.get("klines") or []:
            parts = item.split(",")
            if len(parts) < 5:
                continue
            rows_local.append(
                {
                    "date": str(pd.to_datetime(parts[0]).date()),
                    "open": float(parts[1]),
                    "close": float(parts[2]),
                    "high": float(parts[3]),
                    "low": float(parts[4]),
                }
            )
        return rows_local
    try:
        raw_rows = _eastmoney_kline_rows(fqt=0)
        adj_rows = _eastmoney_kline_rows(fqt=1)
        adj_map = {row["date"]: float(row["close"]) for row in adj_rows}
        for row in raw_rows:
            rows.append(
                {
                    "date": row["date"],
                    "open": float(row["open"]),
                    "close_raw": float(row["close"]),
                    "close_adj": float(adj_map.get(row["date"], row["close"])),
                    "high": float(row["high"]),
                    "low": float(row["low"]),
                }
            )
    except Exception:
        rows = []

    if not rows:
        tencent_symbol = f"sh{symbol}" if symbol.startswith(("5", "6", "9")) else f"sz{symbol}"
        tencent_url = (
            "https://web.ifzq.gtimg.cn/appstock/app/kline/kline"
            f"?param={tencent_symbol},day,,,{max(80, DEFAULT_HISTORY_CALENDAR_DAYS * 2)}"
        )
        try:
            data = fetch_json(tencent_url, timeout=min(DEFAULT_REQUEST_TIMEOUT, 6), retries=2)
            payload = (data.get("data") or {}).get(tencent_symbol) or {}
            klines = payload.get("day") or []
            for item in klines:
                if not isinstance(item, list) or len(item) < 5:
                    continue
                dt = pd.to_datetime(item[0], errors="coerce")
                if pd.isna(dt) or dt < pd.Timestamp(trading_start) or dt > pd.Timestamp(trading_end):
                    continue
                rows.append(
                    {
                        "date": str(dt.date()),
                        "open": float(item[1]),
                        "close_raw": float(item[2]),
                        "close_adj": float(item[2]),
                        "high": float(item[3]),
                        "low": float(item[4]),
                    }
                )
        except Exception:
            rows = []

    if not rows:
        sina_symbol = f"sh{symbol}" if symbol.startswith(("5", "6", "9")) else f"sz{symbol}"
        sina_url = (
            "https://money.finance.sina.com.cn/quotes_service/api/json_v2.php/CN_MarketData.getKLineData"
            f"?symbol={sina_symbol}&scale=240&ma=no&datalen={max(80, DEFAULT_HISTORY_CALENDAR_DAYS * 2)}"
        )
        data = fetch_json(sina_url, timeout=min(DEFAULT_REQUEST_TIMEOUT, 6), retries=2)
        if isinstance(data, list):
            for item in data:
                day = item.get("day")
                close = item.get("close")
                open_px = item.get("open")
                high_px = item.get("high")
                low_px = item.get("low")
                if day is None or close is None:
                    continue
                dt = pd.to_datetime(day)
                if dt < pd.Timestamp(trading_start) or dt > pd.Timestamp(trading_end):
                    continue
                rows.append(
                    {
                        "date": str(dt.date()),
                        "open": float(open_px) if open_px is not None else np.nan,
                        "close_raw": float(close),
                        "close_adj": float(close),
                        "high": float(high_px) if high_px is not None else np.nan,
                        "low": float(low_px) if low_px is not None else np.nan,
                    }
                )
    if not rows:
        raise RuntimeError(f"无法获取个股历史: {symbol}")
    write_json_cache(cache, rows)
    frame = pd.DataFrame(rows)
    frame["date"] = pd.to_datetime(frame["date"])
    return frame


def load_share_change_cache_frame(symbol, end_date, force_refresh=False):
    csv_cache_path = resolve_csv_cache_path(LOCAL_SHARE_CACHE_DIR, SHARED_SHARE_CACHE_DIR, symbol)
    if (not force_refresh) and csv_cache_path is not None:
        try:
            frame = pd.read_csv(csv_cache_path, usecols=["change_date", "total_shares_10k"])
            frame["change_date"] = pd.to_datetime(frame["change_date"], errors="coerce", format="%Y-%m-%d")
            frame["total_shares_10k"] = pd.to_numeric(frame["total_shares_10k"], errors="coerce")
            frame = frame.dropna(subset=["change_date", "total_shares_10k"]).sort_values("change_date")
            frame = frame.loc[frame["change_date"] <= pd.Timestamp(end_date)].copy()
            if not frame.empty:
                return frame
        except Exception:
            pass

    cache = cached_path(f"share_{symbol}.json")
    cached = None if force_refresh else read_json_cache(cache, 30 * 86400)
    if cached is None:
        return None
    frame = pd.DataFrame(cached)
    if frame.empty:
        return None
    frame["change_date"] = pd.to_datetime(frame["change_date"], errors="coerce", format="%Y-%m-%d")
    frame["total_shares_10k"] = pd.to_numeric(frame["total_shares_10k"], errors="coerce")
    frame = frame.dropna(subset=["change_date", "total_shares_10k"]).sort_values("change_date")
    frame = frame.loc[frame["change_date"] <= pd.Timestamp(end_date)].copy()
    return None if frame.empty else frame


def fetch_share_change(symbol, end_date, force_refresh=False):
    cache = cached_path(f"share_{symbol}.json")
    cached_frame = load_share_change_cache_frame(symbol, end_date, force_refresh=force_refresh)
    if cached_frame is not None:
        return cached_frame

    ak = get_akshare()
    frame = call_akshare_silently(
        ak.stock_share_change_cninfo,
        symbol=str(symbol).zfill(6),
        start_date="19900101",
        end_date=pd.Timestamp(end_date).strftime("%Y%m%d"),
    )
    if frame.empty:
        if cached_frame is not None:
            return cached_frame
        raise RuntimeError(f"无法获取股本变更: {symbol}")
    col_date = next((col for col in frame.columns if str(col).strip() in {"变动日期", "公告日期"}), None)
    col_total = next((col for col in frame.columns if str(col).strip() == "总股本"), None)
    col_reason = next((col for col in frame.columns if str(col).strip() == "变动原因"), None)
    if col_date is None or col_total is None:
        raise RuntimeError(f"股本变更字段缺失: {symbol} | columns={list(frame.columns)}")
    keep_cols = [col_date, col_total] + ([col_reason] if col_reason is not None else [])
    frame = frame.loc[:, keep_cols].copy()
    if col_reason is None:
        frame["变动原因"] = ""
        col_reason = "变动原因"
    frame.columns = ["change_date", "total_shares_10k", "reason"]
    frame["change_date"] = pd.to_datetime(frame["change_date"], errors="coerce")
    frame["total_shares_10k"] = pd.to_numeric(frame["total_shares_10k"], errors="coerce")
    frame = frame.dropna(subset=["change_date", "total_shares_10k"]).sort_values("change_date")
    if frame.empty:
        raise RuntimeError(f"股本变更为空: {symbol}")
    write_json_cache(
        cache,
        [
            {
                "change_date": str(pd.Timestamp(row.change_date).date()),
                "total_shares_10k": float(row.total_shares_10k),
                "reason": str(getattr(row, "reason", "") or ""),
            }
            for row in frame.itertuples(index=False)
        ],
    )
    return frame.loc[frame["change_date"] <= pd.Timestamp(end_date)].copy()


def read_ohlc_cache(symbol, start_ts, end_ts):
    required = {"date", "open", "close", "high", "low"}
    for base_dir in (LOCAL_OHLC_CACHE_DIR, SHARED_OHLC_CACHE_DIR):
        if base_dir is None:
            continue
        path = base_dir / f"{str(symbol).zfill(6)}.csv"
        if not path.exists():
            continue
        try:
            frame = pd.read_csv(path)
        except Exception:
            continue
        if not required.issubset(frame.columns):
            continue
        frame["date"] = pd.to_datetime(frame["date"], errors="coerce")
        for col in ["open", "close", "high", "low"]:
            frame[col] = pd.to_numeric(frame[col], errors="coerce")
        frame = frame.dropna(subset=["date", "open", "close", "high", "low"]).sort_values("date")
        frame = frame[(frame["date"] >= pd.Timestamp(start_ts)) & (frame["date"] <= pd.Timestamp(end_ts))].copy()
        if not frame.empty:
            return frame.rename(columns={"close": "close_raw"})
    return pd.DataFrame(columns=["date", "open", "high", "low", "close_raw"])


def fetch_candidate_histories(candidates, trading_start, trading_end, max_workers, min_latest_date=None, force_refresh=False):
    histories = {}
    failures = {}
    symbols = candidates["code"].astype(str).tolist()
    pending = []
    for symbol in symbols:
        frame = load_history_cache_frame(
            symbol,
            trading_start,
            trading_end,
            min_latest_date=min_latest_date,
            force_refresh=force_refresh,
        )
        if frame is not None:
            histories[symbol] = frame
        else:
            pending.append(symbol)

    if not pending:
        return histories, failures

    with ThreadPoolExecutor(max_workers=max(1, min(int(max_workers), 32, len(pending)))) as pool:
        futures = {
            pool.submit(
                eastmoney_stock_history,
                symbol,
                trading_start,
                trading_end,
                min_latest_date,
                force_refresh,
            ): symbol
            for symbol in pending
        }
        for fut in as_completed(futures):
            symbol = futures[fut]
            try:
                frame = fut.result()
                if not frame.empty:
                    histories[symbol] = frame
            except Exception as exc:
                failures[symbol] = str(exc)
    return histories, failures


def build_trade_dates(history_days, force_refresh=False):
    hedge_hist = eastmoney_index_history(HEDGE_SECID, history_days, force_refresh=force_refresh)
    hedge_hist = hedge_hist.sort_values("date").reset_index(drop=True)
    return hedge_hist, pd.DatetimeIndex(hedge_hist["date"])


def build_biweekly_rebalance_dates(trading_dates, week_anchor=REBALANCE_WEEKDAY):
    freq = WEEK_FREQ_BY_START[week_anchor]
    week_periods = trading_dates.to_period(freq)
    unique_weeks = sorted(pd.Index(week_periods.unique()))
    week_keys = pd.Series([i // 2 for i, _ in enumerate(unique_weeks)], index=unique_weeks)
    aligned_keys = pd.Index(week_periods).map(lambda p: week_keys[p])
    grouped = trading_dates.to_series().groupby(aligned_keys)
    return pd.DatetimeIndex(grouped.min().tolist())


def locate_rebalance_dates(trading_dates):
    rebalance_dates = build_biweekly_rebalance_dates(trading_dates)
    last_trade_date = pd.Timestamp(trading_dates[-1])
    available = [pd.Timestamp(dt) for dt in rebalance_dates if pd.Timestamp(dt) <= last_trade_date]
    latest_rebalance = available[-1]
    prev_rebalance = available[-2] if len(available) >= 2 else None
    effective_rebalance = prev_rebalance if latest_rebalance == last_trade_date and prev_rebalance is not None else latest_rebalance
    future = [pd.Timestamp(dt) for dt in rebalance_dates if pd.Timestamp(dt) > last_trade_date]
    next_rebalance = future[0] if future else None
    return latest_rebalance, prev_rebalance, next_rebalance, effective_rebalance


def build_signal_window(trading_dates, lookback=LOOKBACK):
    all_dates = pd.DatetimeIndex(trading_dates)
    if len(all_dates) <= lookback + 1:
        raise RuntimeError("最近交易日数量不足，无法重建信号窗口")

    latest_idx = len(all_dates) - 1
    signal_start_idx = max(0, latest_idx - lookback - 2)
    signal_start_date = pd.Timestamp(all_dates[signal_start_idx])
    rebalance_dates = [pd.Timestamp(dt) for dt in build_biweekly_rebalance_dates(all_dates) if pd.Timestamp(dt) <= all_dates[-1]]

    required_rebalances = []
    prior = [dt for dt in rebalance_dates if dt <= signal_start_date]
    if prior:
        required_rebalances.append(prior[-1])
    required_rebalances.extend([dt for dt in rebalance_dates if dt > signal_start_date])
    required_rebalances = sorted(set(required_rebalances))
    if not required_rebalances:
        required_rebalances = rebalance_dates[-1:]
    if not required_rebalances:
        raise RuntimeError("无法定位信号窗口所需的调仓日期")

    window_start = required_rebalances[0]
    window_dates = all_dates[all_dates >= window_start]
    return pd.DatetimeIndex(window_dates), pd.DatetimeIndex(required_rebalances)


def round_limit_price(value):
    return float(Decimal(str(value)).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP))


def get_price_limit_ratio(symbol, trade_date):
    code = str(symbol).zfill(6)
    if code.startswith(("300", "301")):
        return 0.2 if pd.Timestamp(trade_date) >= CHINEXT_LIMIT_SWITCH else 0.1
    if code.startswith("688"):
        return 0.2
    if code.startswith(("8", "4")):
        return 0.3
    return 0.1


def detect_limit_locks(symbol, trade_date, prev_close, row):
    if pd.isna(prev_close):
        return False, False
    prices = [row.get("open"), row.get("high"), row.get("low"), row.get("close_raw")]
    if any(pd.isna(price) for price in prices):
        return False, False
    ratio = get_price_limit_ratio(symbol, trade_date)
    up_limit = round_limit_price(prev_close * (1.0 + ratio))
    down_limit = round_limit_price(prev_close * (1.0 - ratio))
    up_locked = all(abs(float(price) - up_limit) <= LIMIT_PRICE_EPS for price in prices)
    down_locked = all(abs(float(price) - down_limit) <= LIMIT_PRICE_EPS for price in prices)
    return up_locked, down_locked


def detect_close_limit_blocks(symbol, trade_date, prev_close, close_price):
    if pd.isna(prev_close) or pd.isna(close_price):
        return False, False
    ratio = get_price_limit_ratio(symbol, trade_date)
    up_limit = round_limit_price(prev_close * (1.0 + ratio))
    down_limit = round_limit_price(prev_close * (1.0 - ratio))
    up_blocked = abs(float(close_price) - up_limit) <= LIMIT_PRICE_EPS
    down_blocked = abs(float(close_price) - down_limit) <= LIMIT_PRICE_EPS
    return up_blocked, down_blocked


def build_tradeability_series(symbol, hist, trading_dates):
    close_series = hist.set_index("date")["close_raw"].sort_index()
    if close_series.empty:
        empty_float = pd.Series(np.nan, index=trading_dates, dtype=float)
        empty_bool = pd.Series(False, index=trading_dates, dtype=bool)
        return empty_float, empty_bool, empty_bool.copy(), empty_bool.copy()

    listed_mask = pd.Series(
        (trading_dates >= close_series.index.min()) & (trading_dates <= close_series.index.max()),
        index=trading_dates,
        dtype=bool,
    )
    actual_price_dates = pd.DatetimeIndex(close_series.index)
    close_calendar = close_series.reindex(trading_dates)
    close_calendar = close_calendar.where(listed_mask)
    close_calendar = close_calendar.ffill().where(listed_mask)
    return_col = "close_adj" if "close_adj" in hist.columns else "close_raw"
    return_close_series = hist.set_index("date")[return_col].sort_index()
    return_close_calendar = return_close_series.reindex(trading_dates)
    return_close_calendar = return_close_calendar.where(listed_mask)
    return_close_calendar = return_close_calendar.ffill().where(listed_mask)
    ret_series = return_close_calendar.pct_change(fill_method=None).astype(float)

    ohlc_frame = read_ohlc_cache(symbol, trading_dates.min(), trading_dates.max())
    if ohlc_frame.empty:
        ohlc_frame = hist.reindex(columns=["date", "open", "high", "low", "close_raw"]).copy()
    ohlc_lookup = ohlc_frame.set_index("date").reindex(trading_dates) if not ohlc_frame.empty else pd.DataFrame(index=trading_dates)
    tradeable = pd.Series(trading_dates.isin(actual_price_dates), index=trading_dates, dtype=bool) & listed_mask
    buyable = tradeable.copy()
    sellable = tradeable.copy()
    if TRADE_CONSTRAINT_MODE == "close":
        prev_close = close_calendar.shift(1)
        for dt in trading_dates[tradeable.to_numpy()]:
            up_blocked, down_blocked = detect_close_limit_blocks(
                symbol,
                pd.Timestamp(dt),
                prev_close.loc[dt],
                close_calendar.loc[dt],
            )
            if up_blocked:
                buyable.loc[dt] = False
            if down_blocked:
                sellable.loc[dt] = False
    elif not ohlc_lookup.empty:
        prev_close = close_calendar.shift(1)
        for dt in trading_dates[tradeable.to_numpy()]:
            row = ohlc_lookup.loc[dt]
            if pd.isna(row.get("open")):
                continue
            up_locked, down_locked = detect_limit_locks(symbol, pd.Timestamp(dt), prev_close.loc[dt], row)
            if up_locked:
                buyable.loc[dt] = False
            if down_locked:
                sellable.loc[dt] = False
    return ret_series, tradeable, buyable, sellable


def build_estimated_share_change_frame(row, end_date):
    latest_price = pd.to_numeric(getattr(row, "latest_price", np.nan), errors="coerce")
    market_cap = pd.to_numeric(getattr(row, "market_cap", np.nan), errors="coerce")
    if pd.isna(latest_price) or pd.isna(market_cap) or latest_price <= 0 or market_cap <= 0:
        return pd.DataFrame(columns=["change_date", "total_shares_10k"])
    total_shares_10k = float(market_cap) / float(latest_price) / 10000.0
    if not np.isfinite(total_shares_10k) or total_shares_10k <= 0:
        return pd.DataFrame(columns=["change_date", "total_shares_10k"])
    return pd.DataFrame(
        [
            {
                "change_date": pd.Timestamp(end_date) - pd.Timedelta(days=3650),
                "total_shares_10k": float(total_shares_10k),
            }
        ]
    )


def can_trade_on_day(tradeability_df, trade_date, symbol):
    if symbol not in tradeability_df.columns or trade_date not in tradeability_df.index:
        return False
    value = tradeability_df.at[trade_date, symbol]
    return bool(pd.notna(value) and value)


def apply_trade_constraints(current_members, target_members, trade_date, buyable_df, sellable_df, top_n=TOP_N):
    current_set = set(current_members)
    target_set = set(target_members)

    holdovers = [symbol for symbol in target_members if symbol in current_set]
    exited = []
    blocked_exits = []
    for symbol in current_members:
        if symbol in target_set:
            continue
        if can_trade_on_day(sellable_df, trade_date, symbol):
            exited.append(symbol)
        else:
            blocked_exits.append(symbol)

    buy_candidates = [symbol for symbol in target_members if symbol not in current_set]
    available_slots = max(top_n - len(holdovers) - len(blocked_exits), 0)
    entered = []
    blocked_entries = []
    for symbol in buy_candidates:
        if len(entered) >= available_slots:
            blocked_entries.append(symbol)
            continue
        if can_trade_on_day(buyable_df, trade_date, symbol):
            entered.append(symbol)
        else:
            blocked_entries.append(symbol)

    members_after = holdovers + entered + blocked_exits
    return {
        "members_after": members_after,
        "entered": entered,
        "exited": exited,
        "blocked_entries": blocked_entries,
        "blocked_exits": blocked_exits,
    }


def build_returns_and_caps(candidates, histories, trading_dates, rebalance_dates, force_refresh=False):
    returns_map = {}
    caps_by_date = {}
    buyable_map = {}
    sellable_map = {}
    name_map = dict(zip(candidates["code"].astype(str), candidates["name"]))

    for row in candidates.itertuples(index=False):
        symbol = str(row.code)
        if symbol not in histories:
            continue
        hist = histories[symbol].copy()
        hist["date"] = pd.to_datetime(hist["date"])
        hist["close_raw"] = pd.to_numeric(hist["close_raw"], errors="coerce")
        if "close_adj" in hist.columns:
            hist["close_adj"] = pd.to_numeric(hist["close_adj"], errors="coerce")
        for col in ["open", "high", "low"]:
            if col in hist.columns:
                hist[col] = pd.to_numeric(hist[col], errors="coerce")
        hist = hist.dropna(subset=["close_raw"]).sort_values("date")
        if hist.empty:
            continue

        shares = load_share_change_cache_frame(symbol, trading_dates.max(), force_refresh=False)
        if shares is None and DEFAULT_FETCH_SHARE_CHANGE:
            try:
                shares = fetch_share_change(symbol, trading_dates.max(), force_refresh=force_refresh)
            except Exception:
                shares = None
        if shares is None or shares.empty:
            shares = build_estimated_share_change_frame(row, trading_dates.max())
        if shares.empty:
            continue

        ret_series, tradeable_series, buyable_series, sellable_series = build_tradeability_series(
            symbol,
            hist.copy(),
            trading_dates,
        )
        returns_map[symbol] = ret_series
        buyable_map[symbol] = buyable_series
        sellable_map[symbol] = sellable_series

        cap_lookup = pd.merge_asof(
            pd.DataFrame({"date": rebalance_dates}),
            hist[["date", "close_raw"]].sort_values("date"),
            on="date",
            direction="backward",
        )
        cap_lookup = pd.merge_asof(
            cap_lookup.sort_values("date"),
            shares[["change_date", "total_shares_10k"]].sort_values("change_date"),
            left_on="date",
            right_on="change_date",
            direction="backward",
        )
        cap_lookup["market_cap"] = cap_lookup["close_raw"] * cap_lookup["total_shares_10k"] * 10000.0
        cap_series = cap_lookup.set_index("date")["market_cap"].astype(float)
        cap_tradeable = tradeable_series.reindex(rebalance_dates).fillna(False).astype(bool)
        cap_series = cap_series.where(cap_tradeable, np.nan)
        for dt, cap in cap_series.dropna().items():
            caps_by_date.setdefault(pd.Timestamp(dt), {})[symbol] = float(cap)

    returns_df = pd.DataFrame(returns_map, index=trading_dates) if returns_map else pd.DataFrame(index=trading_dates)
    buyable_df = pd.DataFrame(buyable_map, index=trading_dates) if buyable_map else pd.DataFrame(index=trading_dates)
    sellable_df = pd.DataFrame(sellable_map, index=trading_dates) if sellable_map else pd.DataFrame(index=trading_dates)
    return returns_df, caps_by_date, buyable_df, sellable_df, name_map


def select_members_by_rebalance(caps_by_date, rebalance_dates, name_map):
    members_map = {}
    member_rows = []
    for dt in rebalance_dates:
        cap_map = caps_by_date.get(pd.Timestamp(dt), {})
        ranked = sorted(cap_map.items(), key=lambda x: x[1])[:TOP_N]
        symbols = [symbol for symbol, _ in ranked]
        members_map[pd.Timestamp(dt)] = symbols
        for idx, (symbol, cap) in enumerate(ranked, start=1):
            member_rows.append(
                {
                    "rebalance_date": str(pd.Timestamp(dt).date()),
                    "rank": idx,
                    "symbol": str(symbol).zfill(6),
                    "name": name_map.get(symbol, ""),
                    "market_cap": float(cap),
                    "target_weight": 1.0 / TOP_N,
                }
            )
    return members_map, pd.DataFrame(member_rows)


def build_change_table(prev_df, curr_df):
    prev_df = pd.DataFrame() if prev_df is None else prev_df.copy()
    curr_df = pd.DataFrame() if curr_df is None else curr_df.copy()

    for frame in (prev_df, curr_df):
        if frame.empty:
            continue
        frame["symbol"] = frame["symbol"].astype(str).str.zfill(6)

    prev_map = {}
    if not prev_df.empty:
        prev_map = prev_df.set_index("symbol")[["rank", "name"]].to_dict(orient="index")
    curr_map = {}
    if not curr_df.empty:
        curr_map = curr_df.set_index("symbol")[["rank", "name"]].to_dict(orient="index")

    rows = []
    for symbol in sorted(set(curr_map) - set(prev_map), key=lambda s: curr_map[s]["rank"]):
        rows.append(
            {
                "action": "enter",
                "symbol": symbol,
                "name": curr_map[symbol].get("name", ""),
                "prev_rank": np.nan,
                "new_rank": curr_map[symbol].get("rank", np.nan),
            }
        )
    for symbol in sorted(set(prev_map) - set(curr_map), key=lambda s: prev_map[s]["rank"]):
        rows.append(
            {
                "action": "exit",
                "symbol": symbol,
                "name": prev_map[symbol].get("name", ""),
                "prev_rank": prev_map[symbol].get("rank", np.nan),
                "new_rank": np.nan,
            }
        )
    return pd.DataFrame(rows, columns=["action", "symbol", "name", "prev_rank", "new_rank"])


def build_proxy_index(trading_dates, returns_df, members_map, rebalance_dates, buyable_df, sellable_df):
    rebalance_set = set(pd.DatetimeIndex(rebalance_dates))
    level = 1000.0
    current_members = []
    effective_members_map = {}
    rows = []
    for i, dt in enumerate(trading_dates):
        if i == 0:
            rows.append(
                {
                    "date": dt,
                    "close": level,
                    "daily_return": np.nan,
                    "holding_count": 0,
                    "holding_effective": False,
                }
            )
            continue
        prev_dt = pd.Timestamp(trading_dates[i - 1])
        if prev_dt in rebalance_set:
            trade_result = apply_trade_constraints(
                current_members=current_members,
                target_members=members_map.get(prev_dt, []),
                trade_date=pd.Timestamp(dt),
                buyable_df=buyable_df,
                sellable_df=sellable_df,
                top_n=TOP_N,
            )
            current_members = trade_result["members_after"]
            effective_members_map[prev_dt] = current_members.copy()

        if current_members:
            day_ret = returns_df.loc[dt, current_members].dropna()
            portfolio_ret = float(day_ret.mean()) if len(day_ret) else 0.0
        else:
            portfolio_ret = 0.0
        level *= 1.0 + portfolio_ret
        rows.append(
            {
                "date": dt,
                "close": level,
                "daily_return": portfolio_ret,
                "holding_count": len(current_members),
                "holding_effective": bool(current_members),
            }
        )
    return pd.DataFrame(rows), effective_members_map


def calc_momentum(series, lookback):
    return series.div(series.shift(lookback)).sub(1.0)


def calc_bias_momentum(series, bias_n, mom_day):
    prices = series.values.astype(float)
    result = np.full(len(prices), np.nan)
    ma = series.rolling(bias_n).mean().values
    total_lookback = bias_n + mom_day - 1
    x = np.arange(mom_day, dtype=float)
    for i in range(total_lookback, len(prices)):
        bias_window = np.empty(mom_day)
        valid = True
        for j in range(mom_day):
            idx = i - mom_day + 1 + j
            if np.isnan(ma[idx]) or ma[idx] < 1e-10 or np.isnan(prices[idx]):
                valid = False
                break
            bias_window[j] = prices[idx] / ma[idx]
        if not valid or bias_window[0] < 1e-10:
            continue
        bias_norm = bias_window / bias_window[0]
        slope = np.polyfit(x, bias_norm, 1)[0]
        result[i] = slope * 10000
    return pd.Series(result, index=series.index)


def calc_rolling_r2(series, window):
    values = series.values.astype(float)
    result = np.full(len(values), np.nan)
    x = np.arange(window, dtype=float)
    x_mean = x.mean()
    ss_x = ((x - x_mean) ** 2).sum()
    for i in range(window - 1, len(values)):
        y = values[i - window + 1 : i + 1]
        if np.any(np.isnan(y)):
            continue
        y_mean = y.mean()
        ss_y = ((y - y_mean) ** 2).sum()
        if ss_y < 1e-12:
            result[i] = 0.0
            continue
        ss_xy = ((x - x_mean) * (y - y_mean)).sum()
        result[i] = (ss_xy ** 2) / (ss_x * ss_y)
    return pd.Series(result, index=series.index)


def run_backtest(close_df):
    work = close_df.copy()
    hedge_ratio = get_strategy_base_hedge_ratio()
    work["microcap_ret"] = work["microcap"].pct_change(fill_method=None)
    work["hedge_ret"] = work["hedge"].pct_change(fill_method=None)
    work["microcap_mom"] = calc_momentum(work["microcap"], LOOKBACK)
    work["hedge_mom"] = calc_momentum(work["hedge"], LOOKBACK)
    work["momentum_gap"] = work["microcap_mom"] - work["hedge_mom"]
    work["ratio"] = work["microcap"] / work["hedge"]
    work["ratio_bias_mom"] = calc_bias_momentum(work["ratio"], 60, 20)
    work["ratio_r2"] = calc_rolling_r2(work["ratio"], 5)
    valid_start = work[["microcap_mom", "hedge_mom"]].dropna().index.min()
    if pd.isna(valid_start):
        raise RuntimeError("最近窗口数据不足，无法计算动量信号")

    work = work.loc[valid_start:].copy()
    rows = []
    holding = False
    for i in range(1, len(work)):
        active_ret = 0.0
        drag = FUTURES_DRAG * hedge_ratio if holding else 0.0
        if holding:
            microcap_ret = work["microcap_ret"].iloc[i]
            hedge_ret = work["hedge_ret"].iloc[i]
            if pd.notna(microcap_ret) and pd.notna(hedge_ret):
                active_ret = float(microcap_ret - hedge_ratio * hedge_ret)
        signal_on = bool(
            pd.notna(work["microcap_mom"].iloc[i])
            and pd.notna(work["hedge_mom"].iloc[i])
            and work["microcap_mom"].iloc[i] > work["hedge_mom"].iloc[i]
        )
        next_holding = "long_microcap_short_zz1000" if signal_on else "cash"
        rows.append(
            {
                "date": work.index[i],
                "return_raw": active_ret - drag,
                "holding": "long_microcap_short_zz1000" if holding else "cash",
                "next_holding": next_holding,
                "microcap_close": float(work["microcap"].iloc[i]),
                "hedge_close": float(work["hedge"].iloc[i]),
                "microcap_mom": float(work["microcap_mom"].iloc[i]),
                "hedge_mom": float(work["hedge_mom"].iloc[i]),
                "momentum_gap": float(work["momentum_gap"].iloc[i]),
                "ratio_bias_mom": float(work["ratio_bias_mom"].iloc[i]) if pd.notna(work["ratio_bias_mom"].iloc[i]) else np.nan,
                "ratio_r2": float(work["ratio_r2"].iloc[i]) if pd.notna(work["ratio_r2"].iloc[i]) else np.nan,
                "hedge_ratio": hedge_ratio,
                "weight": 1.0,
                "futures_drag": drag,
            }
        )
        holding = signal_on
    result = pd.DataFrame(rows).set_index("date")
    result["return"] = result["return_raw"]
    result["nav"] = (1.0 + result["return"]).cumprod()
    if is_nav_control_strategy() and not result.empty:
        control = compute_nav_control_state(result["return"])
        result["return_base"] = result["return"]
        result["nav_base"] = result["nav"]
        result["nav_control_scale"] = control["throttle"]["scale"]
        result["nav_control_state"] = control["throttle"]["state"]
        result["nav_control_prev_drawdown"] = control["throttle"]["prev_drawdown"]
        result["nav_control_turnover"] = control["throttle"]["turnover"]
        result["nav_control_cost"] = control["throttle"]["cost"]
        result["return"] = control["throttle"]["return"]
        result["nav"] = control["nav"]
    return result


def build_latest_signal(result):
    last = result.iloc[[-1]].copy().reset_index()
    last["signal_label"] = np.where(last["next_holding"] == "cash", "cash", "long_microcap_short_zz1000")
    annotated = annotate_trade_states(result)
    current_holding = str(result.iloc[-1]["holding"])
    trade_state = str(annotated.iloc[-1]["trade_state_calc"])
    last["current_holding"] = current_holding
    last["trade_state"] = trade_state
    extra_cols = []
    if "nav_control_scale" in result.columns:
        control = compute_nav_control_state(result["return_base"] if "return_base" in result.columns else result["return"])
        next_holding = str(last.iloc[0]["next_holding"])
        last["nav_control_scale_last_applied"] = control["last_scale"]
        last["nav_control_state_last_applied"] = control["last_state"]
        last["nav_control_drawdown_last_close"] = control["current_dd"]
        last["nav_control_scale_next_session"] = control["next_scale"]
        last["nav_control_state_next_session"] = control["next_state"]
        last["effective_hedge_ratio_last_applied"] = (
            get_strategy_base_hedge_ratio() * control["last_scale"] if current_holding != "cash" else 0.0
        )
        last["effective_hedge_ratio_next_session"] = (
            get_strategy_base_hedge_ratio() * control["next_scale"] if next_holding != "cash" else 0.0
        )
        last["nav_control_config"] = "4/8 + 0.85/0.70 + recover 3%"
        extra_cols = [
            "nav_control_scale_last_applied",
            "nav_control_state_last_applied",
            "nav_control_drawdown_last_close",
            "nav_control_scale_next_session",
            "nav_control_state_next_session",
            "effective_hedge_ratio_last_applied",
            "effective_hedge_ratio_next_session",
            "nav_control_config",
        ]
    base_cols = [
        "date",
        "signal_label",
        "next_holding",
        "microcap_close",
        "hedge_close",
        "microcap_mom",
        "hedge_mom",
        "momentum_gap",
        "ratio_bias_mom",
        "ratio_r2",
        "hedge_ratio",
        "weight",
        "futures_drag",
        "current_holding",
        "trade_state",
    ]
    return last[base_cols + extra_cols]


def infer_proxy_effective_start(proxy_df):
    if proxy_df.empty:
        return None
    proxy = proxy_df.sort_values("date").copy()
    if "holding_effective" in proxy.columns:
        mask = proxy["holding_effective"].fillna(False).astype(bool)
        if mask.any():
            return pd.Timestamp(proxy.loc[mask, "date"].iloc[0])
    if "holding_count" in proxy.columns:
        holding_count = pd.to_numeric(proxy["holding_count"], errors="coerce").fillna(0)
        mask = holding_count.gt(0)
        if mask.any():
            return pd.Timestamp(proxy.loc[mask, "date"].iloc[0])
    return None


def assemble_context(hedge_hist, all_trading_dates, candidates, histories, failures, pool_size, stage_attempts, force_refresh=False):
    window_dates, required_rebalances = build_signal_window(all_trading_dates)
    returns_df, caps_by_date, buyable_df, sellable_df, name_map = build_returns_and_caps(
        candidates,
        histories,
        window_dates,
        required_rebalances,
        force_refresh=force_refresh,
    )
    members_map, members_df = select_members_by_rebalance(caps_by_date, required_rebalances, name_map)
    proxy_df, _ = build_proxy_index(
        window_dates,
        returns_df,
        members_map,
        required_rebalances,
        buyable_df,
        sellable_df,
    )
    effective_start = infer_proxy_effective_start(proxy_df)
    if effective_start is not None:
        proxy_df = proxy_df.loc[proxy_df["date"] >= effective_start].copy()
        members_df = members_df.loc[pd.to_datetime(members_df["rebalance_date"]) >= effective_start].copy()

    close_df = proxy_df[["date", "close"]].rename(columns={"close": "microcap"}).merge(
        hedge_hist[hedge_hist["date"].isin(window_dates)].rename(columns={"close": "hedge"}),
        on="date",
        how="inner",
    )
    close_df = close_df.sort_values("date").set_index("date").dropna()
    result = run_backtest(close_df)
    latest_signal = build_latest_signal(result)
    latest_rebalance, prev_rebalance, next_rebalance, effective_rebalance = locate_rebalance_dates(all_trading_dates)
    target_members = members_df.loc[members_df["rebalance_date"] == str(pd.Timestamp(latest_rebalance).date())].copy()
    prev_members = None
    if prev_rebalance is not None:
        prev_members = members_df.loc[members_df["rebalance_date"] == str(pd.Timestamp(prev_rebalance).date())].copy()
    effective_members = members_df.loc[members_df["rebalance_date"] == str(pd.Timestamp(effective_rebalance).date())].copy()

    rebalance_idx = pd.DatetimeIndex(all_trading_dates).get_loc(pd.Timestamp(latest_rebalance))
    effective_date = (
        str(pd.Timestamp(all_trading_dates[rebalance_idx + 1]).date())
        if rebalance_idx + 1 < len(all_trading_dates)
        else None
    )

    freshness = {
        "status": "正常",
        "latest_trade_date": str(pd.Timestamp(close_df.index[-1]).date()),
        "current_date": str(pd.Timestamp.now().normalize().date()),
        "stale_calendar_days": max(0, int((pd.Timestamp.now().normalize() - pd.Timestamp(close_df.index[-1]).normalize()).days)),
    }
    if not target_members.empty:
        target_members["signal_date"] = str(pd.Timestamp(latest_rebalance).date())
        target_members["effective_date"] = effective_date
    changes_df = build_change_table(prev_members, target_members)
    if not changes_df.empty:
        changes_df["signal_date"] = str(pd.Timestamp(latest_rebalance).date())
        changes_df["effective_date"] = effective_date
    latest_signal = augment_signal_with_member_rebalance(latest_signal, changes_df)
    return {
        "close_df": close_df,
        "result": result,
        "latest_signal": latest_signal,
        "latest_rebalance": str(pd.Timestamp(latest_rebalance).date()),
        "prev_rebalance": None if prev_rebalance is None else str(pd.Timestamp(prev_rebalance).date()),
        "next_rebalance": None if next_rebalance is None else str(pd.Timestamp(next_rebalance).date()),
        "effective_rebalance": str(pd.Timestamp(effective_rebalance).date()),
        "rebalance_effective_date": effective_date,
        "target_members": target_members,
        "effective_members": effective_members,
        "changes_df": changes_df,
        "freshness": freshness,
        "rebuild_meta": {
            "strategy_version": get_strategy()["version"],
            "strategy_label": get_strategy_label(),
            "fixed_hedge_ratio": get_strategy_hedge_ratio(),
            "last_trade_signal_date": None,
            "last_trade_signal_action": None,
            "candidate_pool": int(pool_size),
            "history_symbols_ok": int(len(histories)),
            "history_symbols_failed": int(len(failures)),
            "rebalance_count": int(len(required_rebalances)),
            "effective_member_count": int(len(effective_members)),
            "stage_attempts": [int(x) for x in stage_attempts],
            "window_trade_days": int(len(window_dates)),
        },
    }
    last_trade_date, last_trade_action = get_last_trade_signal_info(context)
    context["rebuild_meta"]["last_trade_signal_date"] = last_trade_date
    context["rebuild_meta"]["last_trade_signal_action"] = last_trade_action
    return context


def build_context(force_refresh=False, require_latest=False):
    cached_context = read_context_cache(force_refresh=force_refresh)
    hedge_hist = None
    all_trading_dates = None
    latest_trade_date = None

    if require_latest:
        hedge_hist, all_trading_dates = build_trade_dates(
            DEFAULT_HISTORY_CALENDAR_DAYS,
            force_refresh=True,
        )
        latest_trade_date = pd.Timestamp(all_trading_dates[-1])
        if (
            cached_context is not None
            and is_context_fresh_for_trade_date(cached_context, latest_trade_date)
            and has_complete_member_tables(cached_context)
        ):
            return cached_context
    elif cached_context is not None and has_complete_member_tables(cached_context):
        return cached_context

    start_ts = time.time()
    if hedge_hist is None or all_trading_dates is None:
        hedge_hist, all_trading_dates = build_trade_dates(
            DEFAULT_HISTORY_CALENDAR_DAYS,
            force_refresh=force_refresh,
        )
    window_dates, _ = build_signal_window(all_trading_dates)
    universe = fetch_universe_spot(
        cache_seconds=0 if (force_refresh or require_latest) else DEFAULT_QUOTE_CACHE_SECONDS
    )
    if latest_trade_date is None:
        latest_trade_date = pd.Timestamp(all_trading_dates[-1])

    pool_stages = []
    for size in DEFAULT_POOL_STAGES + [DEFAULT_CANDIDATE_POOL]:
        size = max(TOP_N, int(size))
        if size not in pool_stages:
            pool_stages.append(size)

    best_context = None
    best_score = (-1, -1, -1)
    exact_contexts = []
    stage_attempts = []
    for pool_size in pool_stages:
        elapsed = time.time() - start_ts
        if STRICT_EXACT_MODE and elapsed >= DEFAULT_TIME_BUDGET_SECONDS:
            if exact_contexts:
                break
            raise RuntimeError(
                f"严格模式超时保护：{int(elapsed)} 秒内未完成精确校验，"
                "为避免 Poe 超时与实盘误判，本次拒绝输出信号。"
            )
        stage_attempts.append(pool_size)
        candidates = select_candidate_pool(universe, pool_size, min_latest_date=latest_trade_date)
        histories, failures = fetch_candidate_histories(
            candidates,
            window_dates.min(),
            window_dates.max(),
            DEFAULT_MAX_WORKERS,
            min_latest_date=latest_trade_date,
            force_refresh=force_refresh,
        )
        try:
            context = assemble_context(
                hedge_hist,
                all_trading_dates,
                candidates,
                histories,
                failures,
                pool_size,
                stage_attempts,
                force_refresh=force_refresh,
            )
        except Exception:
            continue

        score = (
            int(context["rebuild_meta"].get("effective_member_count", 0)),
            int(context["rebuild_meta"].get("history_symbols_ok", 0)),
            -int(pool_size),
        )
        if score > best_score:
            best_context = context
            best_score = score
        if is_exact_context(context):
            exact_contexts.append(context)
        if (not STRICT_EXACT_MODE) and score[0] >= DEFAULT_MIN_ACCEPTABLE_MEMBERS:
            write_context_cache(context)
            return context

    if best_context is None:
        raise RuntimeError("自动重建失败，未能得到可用的 Top100 名单与代理指数")
    if STRICT_EXACT_MODE:
        if not exact_contexts:
            got_members = int(best_context["rebuild_meta"].get("effective_member_count", 0))
            got_pool = int(best_context["rebuild_meta"].get("candidate_pool", 0))
            got_ok = int(best_context["rebuild_meta"].get("history_symbols_ok", 0))
            raise RuntimeError(
                f"严格模式未通过：仅重建出 {got_members}/{TOP_N} 个生效成分股，"
                f"候选池={got_pool}，成功历史数={got_ok}。为避免实盘误判，本次不返回近似信号。"
            )

        signatures = {context_signal_signature(ctx) for ctx in exact_contexts}
        if len(signatures) != 1:
            raise RuntimeError(
                f"严格模式未通过：不同候选池下得到的精确结果不一致（共 {len(signatures)} 种信号），"
                "为避免实盘误判，本次拒绝输出信号。"
            )

        final_context = sorted(
            exact_contexts,
            key=lambda ctx: int((ctx.get("rebuild_meta") or {}).get("candidate_pool", 0)),
        )[-1]
        final_context["rebuild_meta"]["strict_validated"] = True
        final_context["rebuild_meta"]["validated_exact_pools"] = [
            int((ctx.get("rebuild_meta") or {}).get("candidate_pool", 0)) for ctx in exact_contexts
        ]
        final_context["rebuild_meta"]["signal_consensus"] = True
        write_context_cache(final_context)
        return final_context
    write_context_cache(best_context)
    return best_context


def fetch_eastmoney_stock_spot(symbol):
    market = "1" if str(symbol).startswith(("5", "6", "9")) else "0"
    url = (
        "https://push2.eastmoney.com/api/qt/stock/get"
        f"?secid={market}.{str(symbol).zfill(6)}"
        "&fields=f43,f44,f45,f46,f57,f58,f60"
    )
    try:
        data = fetch_json(url, headers={"Referer": "https://quote.eastmoney.com/"})
        data = data.get("data") or {}
        latest = pd.to_numeric(data.get("f43"), errors="coerce")
        prev = pd.to_numeric(data.get("f60"), errors="coerce")
        if pd.notna(latest) and latest > 0:
            rt_price = float(latest) / 100.0
        elif pd.notna(prev) and prev > 0:
            rt_price = float(prev) / 100.0
        else:
            return None
        return {"code": str(data.get("f57") or symbol).zfill(6), "name": str(data.get("f58") or ""), "rt_price": rt_price}
    except Exception:
        return None


def fetch_realtime_quotes(member_symbols):
    rows = []
    with ThreadPoolExecutor(max_workers=max(1, min(DEFAULT_MAX_WORKERS, 32))) as pool:
        futures = {pool.submit(fetch_eastmoney_stock_spot, symbol): symbol for symbol in member_symbols}
        for fut in as_completed(futures):
            row = fut.result()
            if row is not None:
                rows.append(row)
    return pd.DataFrame(rows)


def fetch_hedge_realtime_quote():
    url = (
        "https://push2.eastmoney.com/api/qt/stock/get"
        f"?secid={HEDGE_SECID}"
        "&fields=f43,f60"
    )
    data = fetch_json(url, headers={"Referer": "https://quote.eastmoney.com/"})
    data = data.get("data") or {}
    latest = pd.to_numeric(data.get("f43"), errors="coerce")
    prev = pd.to_numeric(data.get("f60"), errors="coerce")
    if pd.notna(latest) and latest > 0:
        return float(latest) / 100.0
    if pd.notna(prev) and prev > 0:
        return float(prev) / 100.0
    raise RuntimeError("无法获取对冲腿实时价格")


