def format_table_text(df, max_rows=20):
    frame = pd.DataFrame() if df is None else df.copy()
    if frame.empty:
        return "无数据"
    if len(frame) > max_rows:
        frame = frame.head(max_rows)
    for col in frame.columns:
        if pd.api.types.is_datetime64_any_dtype(frame[col]):
            frame[col] = pd.to_datetime(frame[col]).dt.strftime("%Y-%m-%d")
    return frame.to_string(index=False)


def build_csv_bytes(frame):
    return pd.DataFrame(frame).to_csv(index=False).encode("utf-8-sig")


