def handle_realtime_signal(force_refresh=False):
    context = build_context(force_refresh=force_refresh, require_latest=True)
    member_symbols = context["effective_members"]["symbol"].astype(str).str.zfill(6).tolist()
    if not member_symbols:
        raise RuntimeError("自动重建后未得到当前生效成分股")
    if STRICT_EXACT_MODE and len(member_symbols) != TOP_N:
        raise RuntimeError(
            f"严格模式未通过：当前仅有 {len(member_symbols)}/{TOP_N} 个生效成分股，拒绝输出实时信号。"
        )

    last_close_map = {}
    close_df = context["close_df"]
    histories_cache_date = close_df.index.max()

    universe = fetch_universe_spot(cache_seconds=0)
    candidates = universe[universe["code"].isin(member_symbols)].copy()
    histories, _ = fetch_candidate_histories(
        candidates,
        histories_cache_date - pd.Timedelta(days=5),
        histories_cache_date,
        DEFAULT_MAX_WORKERS,
        min_latest_date=histories_cache_date,
        force_refresh=force_refresh,
    )
    for sym in member_symbols:
        hist = histories.get(sym)
        if hist is None or hist.empty:
            continue
        hist["date"] = pd.to_datetime(hist["date"])
        hist = hist[hist["date"] <= histories_cache_date].sort_values("date")
        if not hist.empty:
            last_close_map[sym] = float(hist.iloc[-1]["close_raw"])

    quotes_df = candidates[["code", "name", "latest_price"]].copy()
    quotes_df = quotes_df.rename(columns={"latest_price": "rt_price"})
    if quotes_df.empty:
        raise RuntimeError("无法获取当前生效成分股实时行情")
    quotes_df = quotes_df.set_index("code")
    member_returns = []
    available_rows = 0
    for sym in member_symbols:
        last_close = last_close_map.get(sym)
        if last_close is None or last_close <= 0 or sym not in quotes_df.index:
            continue
        rt_price = pd.to_numeric(quotes_df.at[sym, "rt_price"], errors="coerce")
        if pd.isna(rt_price) or rt_price <= 0:
            continue
        member_returns.append(float(rt_price / last_close - 1.0))
        available_rows += 1
    if not member_returns:
        raise RuntimeError("没有足够的成分股实时价格来估算微盘代理")
    if STRICT_EXACT_MODE and available_rows != TOP_N:
        raise RuntimeError(
            f"严格模式未通过：实时有效报价仅 {available_rows}/{TOP_N}，拒绝输出实时信号。"
        )

    microcap_rt_close = float(close_df["microcap"].iloc[-1]) * (1.0 + float(np.mean(member_returns)))
    hedge_rt_close = fetch_hedge_realtime_quote()

    snapshot_ts = pd.Timestamp.now()
    anchor_trade_date = pd.Timestamp(close_df.index[-1])
    if snapshot_ts <= anchor_trade_date:
        snapshot_ts = anchor_trade_date + pd.Timedelta(seconds=1)
    rt_close_df = close_df.copy()
    rt_close_df.loc[snapshot_ts, ["microcap", "hedge"]] = [microcap_rt_close, hedge_rt_close]
    rt_close_df = rt_close_df.sort_index()
    rt_result = run_backtest(rt_close_df)
    signal_df = build_latest_signal(rt_result)
    signal_df = augment_signal_with_member_rebalance(signal_df, context.get("changes_df"))
    jitter_level, jitter_note = classify_tail_jitter_risk(float(signal_df.iloc[0]["momentum_gap"]))
    signal_df["quote_source"] = "eastmoney"
    signal_df["hedge_quote_source"] = "eastmoney"
    signal_df["member_price_count"] = available_rows
    signal_df["member_count"] = len(member_symbols)
    signal_df["latest_anchor_trade_date"] = str(pd.Timestamp(close_df.index[-1]).date())
    signal_df["tail_jitter_risk"] = jitter_level
    signal_df["tail_jitter_note"] = jitter_note
    csv_bytes = signal_df.to_csv(index=False).encode("utf-8-sig")
    return format_realtime_summary(signal_df.iloc[0], context, available_rows, len(member_symbols)), csv_bytes


