def build_realtime_members(context):
    universe = fetch_universe_spot(cache_seconds=0)
    realtime_members = select_candidate_pool(universe, TOP_N).copy()
    realtime_members = realtime_members.sort_values("market_cap").reset_index(drop=True)
    realtime_members["rank"] = np.arange(1, len(realtime_members) + 1)
    realtime_members["symbol"] = realtime_members["code"].astype(str).str.zfill(6)
    realtime_members["rt_price"] = realtime_members["latest_price"]
    realtime_members["target_weight"] = 1.0 / TOP_N
    realtime_members["signal_date"] = context["latest_rebalance"]
    realtime_members["effective_date"] = context["rebalance_effective_date"]
    return realtime_members[
        [
            "rank",
            "symbol",
            "name",
            "rt_price",
            "market_cap",
            "target_weight",
            "signal_date",
            "effective_date",
        ]
    ].copy()


def handle_realtime_changes(force_refresh=False):
    context = build_context(force_refresh=force_refresh, require_latest=True)
    realtime_members = build_realtime_members(context)
    current_members = context["effective_members"][["symbol", "rank", "name"]].copy()
    changes_df = build_change_table(current_members, realtime_members[["symbol", "rank", "name"]])
    if not changes_df.empty:
        rt_cap_map = dict(zip(realtime_members["symbol"], realtime_members["market_cap"]))
        rt_price_map = dict(zip(realtime_members["symbol"], realtime_members["rt_price"]))
        changes_df["realtime_market_cap"] = changes_df["symbol"].map(rt_cap_map)
        changes_df["realtime_price"] = changes_df["symbol"].map(rt_price_map)
        changes_df["signal_date"] = context["latest_rebalance"]
        changes_df["effective_date"] = context["rebalance_effective_date"]
    attachments = [
        (versioned_attachment_name("microcap_top100_autorebuild_realtime_changes.csv"), build_csv_bytes(changes_df), "text/csv"),
        (versioned_attachment_name("microcap_top100_autorebuild_realtime_members.csv"), build_csv_bytes(realtime_members), "text/csv"),
    ]
    body = format_changes_summary(
        "实时进出名单",
        context,
        changes_df,
        snapshot_time=pd.Timestamp.now().strftime("%Y-%m-%d %H:%M:%S"),
    )
    return body, attachments


def normalize_command(query_text):
    text = (query_text or "").strip()
    if not text:
        return CMD_SIGNAL
    if PERFORMANCE_PATTERN.search(text):
        return CMD_PERFORMANCE
    if "实时" in text and "进出名单" in text:
        return CMD_REALTIME_CHANGES
    if "进出名单" in text:
        return CMD_CHANGES
    if "成分股" in text:
        return CMD_MEMBERS
    if "实时" in text and "信号" in text:
        return CMD_REALTIME
    if "信号" in text:
        return CMD_SIGNAL
    return "help"


def send_message(text, file_name=None, file_bytes=None, attachments=None):
    if file_name and file_bytes is not None:
        (COMMAND_OUTPUT_DIR / file_name).write_bytes(file_bytes)
    for name, content, _ in attachments or []:
        (COMMAND_OUTPUT_DIR / name).write_bytes(content)
    if poe is None or not hasattr(poe, "start_message"):
        print(text)
        if file_name and file_bytes is not None:
            print(f"[file] {file_name} ({len(file_bytes)} bytes)")
        for name, content, content_type in attachments or []:
            print(f"[file] {name} ({len(content)} bytes, {content_type})")
        return
    with poe.start_message() as msg:
        msg.write(text)
        if file_name and file_bytes is not None:
            msg.attach_file(name=file_name, contents=file_bytes, content_type="text/csv")
        for name, content, content_type in attachments or []:
            msg.attach_file(name=name, contents=content, content_type=content_type)

def main():
    if poe is not None and hasattr(poe, "query") and getattr(poe, "query", None) is not None:
        raw_query_text = (poe.query.text or "").strip()
    else:
        raw_query_text = " ".join(sys.argv[1:]).strip()

    strategy, query_text = resolve_strategy_from_query(raw_query_text)
    set_active_strategy(strategy["version"])
    command = normalize_command(query_text)
    force_refresh = False
    if command == "help":
        send_message(
            "支持命令：\n"
            f"1. {CMD_SIGNAL}\n"
            f"2. {CMD_REALTIME}\n"
            f"3. {CMD_MEMBERS}\n"
            f"4. {CMD_CHANGES}\n"
            f"5. {CMD_REALTIME_CHANGES}\n"
            f"6. {CMD_PERFORMANCE} 近5年 / {CMD_PERFORMANCE} 2024至今 / 最近三年表现\n\n"
            "版本写法：命令前后都可加 1.0 / 1.1 / 1.2。\n"
            "示例：`1.2 信号`、`实时信号 1.0`、`表现 1.1 近5年`。\n"
            "说明：该版本会在线自动重建最近窗口的 Top100 名单与代理指数，并支持自然语言表现查询。"
        )
        return

    try:
        if command == CMD_PERFORMANCE:
            body, attachments = build_performance_outputs(query_text)
            send_message(f"## 表现\n\n```text\n{body}\n```", attachments=attachments)
        elif command == CMD_MEMBERS:
            body, csv_bytes = handle_members(force_refresh=force_refresh)
            send_message(
                f"## 成分股\n\n```text\n{body}\n```",
                versioned_attachment_name("microcap_top100_autorebuild_members.csv"),
                csv_bytes,
            )
        elif command == CMD_CHANGES:
            body, csv_bytes = handle_changes(force_refresh=force_refresh)
            send_message(
                f"## 进出名单\n\n```text\n{body}\n```",
                versioned_attachment_name("microcap_top100_autorebuild_changes.csv"),
                csv_bytes,
            )
        elif command == CMD_REALTIME_CHANGES:
            body, attachments = handle_realtime_changes(force_refresh=force_refresh)
            send_message(f"## 实时进出名单\n\n```text\n{body}\n```", attachments=attachments)
        elif command == CMD_REALTIME:
            body, csv_bytes = handle_realtime_signal(force_refresh=force_refresh)
            send_message(
                f"## 实时信号\n\n```text\n{body}\n```",
                versioned_attachment_name("microcap_top100_autorebuild_realtime_signal.csv"),
                csv_bytes,
            )
        else:
            body, csv_bytes = handle_signal(force_refresh=force_refresh)
            send_message(
                f"## 收盘确认信号\n\n```text\n{body}\n```",
                versioned_attachment_name("microcap_top100_autorebuild_signal.csv"),
                csv_bytes,
            )
    except Exception as exc:
        send_message(f"计算失败：{exc}")


update_settings()


if __name__ == "__main__":
    main()
